style:
.svc-hub {
  font-family: "Space Grotesk", "Inter", sans-serif;
  color: #1b1b1b;
}

.svc-hero {
  background: linear-gradient(135deg, #6b7eea, #6a4dbb);
  border-radius: 22px;
  padding: 28px 32px;
  color: #fff;
  display: flex;
  align-items: center;
  gap: 16px;
  margin-bottom: 22px;
  box-shadow: 0 16px 40px rgba(48, 35, 78, 0.3);
  position: relative;
  overflow: hidden;
}

.svc-hero::after {
  content: "";
  position: absolute;
  right: -80px;
  top: -60px;
  width: 240px;
  height: 240px;
  background: radial-gradient(circle, rgba(255,255,255,0.35), rgba(255,255,255,0));
  pointer-events: none;
}

.svc-hero-icon {
  width: 64px;
  height: 64px;
  border-radius: 18px;
  background: rgba(255, 255, 255, 0.22);
  backdrop-filter: blur(6px);
  display: grid;
  place-items: center;
  font-size: 30px;
}

.svc-hero-text h2 {
  margin: 0;
  font-size: 26px;
  font-weight: 600;
}

.svc-hero-text p {
  margin: 4px 0 0 0;
  opacity: 0.9;
  font-size: 13px;
}

.svc-cards {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
  gap: 18px;
}

.svc-tile {
  background: #fff;
  border-radius: 18px;
  padding: 18px;
  display: flex;
  gap: 14px;
  align-items: center;
  text-decoration: none;
  color: inherit;
  box-shadow: 0 10px 24px rgba(17, 24, 39, 0.1);
  border: 1px solid #eef0f4;
  transition: transform 0.2s ease, box-shadow 0.2s ease, border-color 0.2s ease;
  position: relative;
}

.svc-tile:hover {
  transform: translateY(-6px);
  box-shadow: 0 16px 32px rgba(17, 24, 39, 0.16);
  border-color: rgba(107, 126, 234, 0.4);
}

.svc-tile-icon {
  width: 54px;
  height: 54px;
  border-radius: 16px;
  display: grid;
  place-items: center;
  font-size: 24px;
  background: #f3f4ff;
  box-shadow: inset 0 0 0 1px rgba(107, 126, 234, 0.15);
}

.svc-tile-master .svc-tile-icon {
  background: linear-gradient(135deg, #eaf2ff, #f5f8ff);
}

.svc-tile-report .svc-tile-icon {
  background: linear-gradient(135deg, #f3ecff, #fbf8ff);
}

.svc-tile-body h4 {
  margin: 0;
  font-size: 16px;
  font-weight: 600;
}

.svc-tile-body p {
  margin: 4px 0 0 0;
  font-size: 12px;
  color: #6b6b6b;
}

.svc-tile-badge {
  position: absolute;
  top: 12px;
  right: 12px;
  font-size: 11px;
  padding: 4px 8px;
  border-radius: 999px;
  background: rgba(107, 126, 234, 0.12);
  color: #4c5bd4;
  border: 1px solid rgba(107, 126, 234, 0.2);
}

.svc-tile-report .svc-tile-badge {
  background: rgba(106, 77, 187, 0.12);
  color: #6a4dbb;
  border-color: rgba(106, 77, 187, 0.2);
}

.svc-tile-arrow {
  margin-left: auto;
  font-size: 18px;
  color: #9aa0a6;
  transition: transform 0.2s ease, color 0.2s ease;
}

.svc-tile:hover .svc-tile-arrow {
  transform: translateX(4px);
  color: #6b7eea;
}

script:
(function () {
  const shell = root_element.querySelector('.hr-ao-shell');
  if (!shell) return;

  const state = { charts: {} };

  const loadApexCharts = () => {
    if (window.ApexCharts) return Promise.resolve();
    if (window.__hrAoApexPromise) return window.__hrAoApexPromise;
    window.__hrAoApexPromise = new Promise((resolve, reject) => {
      const script = document.createElement('script');
      script.src = '/assets/management_dashboard/js/apexcharts.min.js';
      script.onload = resolve;
      script.onerror = reject;
      document.head.appendChild(script);
    });
    return window.__hrAoApexPromise;
  };

  const formatNumber = (value, decimals = 0) => frappe.format(value || 0, { fieldtype: decimals ? 'Float' : 'Int', precision: decimals || undefined });
  const formatHours = (value) => `${formatNumber(value || 0, 2)} hrs`;

  const kpiMarkup = (label, value, meta) => `
    <div class="hr-ao-kpi">
      <div class="hr-ao-kpi-label">${label}</div>
      <div class="hr-ao-kpi-value">${value}</div>
      <div class="hr-ao-kpi-meta">${meta}</div>
    </div>
  `;

  const renderKpis = (data) => {
    const info = data.kpis || {};
    shell.querySelector('.hr-ao-kpis').innerHTML = [
      kpiMarkup('Present', formatNumber(info.present_days || 0, 2), info.month_label || ''),
      kpiMarkup('Late', formatNumber(info.late_marks || 0, 2), 'Employee Attendance'),
      kpiMarkup('Absent', formatNumber(info.absents || 0, 2), 'Employee Attendance'),
      kpiMarkup('Early', formatNumber(info.early_goings || 0, 2), 'Employee Attendance'),
      kpiMarkup('Missed Check In', formatNumber(info.missed_check_in || 0, 2), 'Absent on missing in'),
      kpiMarkup('Missed Check Out', formatNumber(info.missed_check_out || 0, 2), 'Absent on missing out'),
      kpiMarkup('Overtime', formatHours(info.attendance_overtime_hours || 0), 'Actual overtime'),
      kpiMarkup('Approved OT', formatHours(info.approved_overtime_hours || 0), 'Marked overtime')
    ].join('');
  };

  const destroyCharts = () => {
    Object.values(state.charts).forEach((chart) => {
      try { chart.destroy(); } catch (e) {}
    });
    state.charts = {};
  };

  const baseOptions = (categories) => ({
    chart: { height: 320, toolbar: { show: false }, fontFamily: 'Space Grotesk, Inter, sans-serif' },
    dataLabels: { enabled: false },
    grid: { borderColor: 'rgba(122, 128, 140, 0.14)' },
    xaxis: { categories: categories || [] },
    legend: { position: 'top' },
    stroke: { width: 3, curve: 'smooth' },
    tooltip: { shared: true }
  });

  const renderCharts = (data) => {
    destroyCharts();

    state.charts.status = new ApexCharts(shell.querySelector('[data-chart="status"]'), {
      ...baseOptions(data.months),
      chart: { ...baseOptions(data.months).chart, type: 'bar', stacked: true },
      colors: ['#0f766e', '#f59e0b', '#dc2626', '#7c3aed'],
      plotOptions: { bar: { columnWidth: '50%', borderRadius: 6 } },
      series: [
        { name: 'Present', data: data.present_days || [] },
        { name: 'Late', data: data.late_marks || [] },
        { name: 'Absent', data: data.absents || [] },
        { name: 'Early', data: data.early_goings || [] }
      ]
    });

    state.charts.overtime = new ApexCharts(shell.querySelector('[data-chart="overtime"]'), {
      ...baseOptions(data.months),
      chart: { ...baseOptions(data.months).chart, type: 'line' },
      colors: ['#ef4444', '#f97316', '#2563eb', '#7c3aed'],
      series: [
        { name: 'Missed Check In', type: 'column', data: data.missed_check_in || [] },
        { name: 'Missed Check Out', type: 'column', data: data.missed_check_out || [] },
        { name: 'Overtime', type: 'line', data: data.attendance_overtime_hours || [] },
        { name: 'Approved OT', type: 'line', data: data.approved_overtime_hours || [] }
      ],
      yaxis: [
        { title: { text: 'Missing Counts' } },
        { opposite: true, title: { text: 'Hours' } }
      ]
    });

    state.charts.department = new ApexCharts(shell.querySelector('[data-chart="department"]'), {
      ...baseOptions(data.department_labels),
      chart: { ...baseOptions(data.department_labels).chart, type: 'bar' },
      colors: ['#0891b2', '#0f766e', '#f59e0b', '#dc2626'],
      plotOptions: { bar: { horizontal: true, borderRadius: 6, barHeight: '62%' } },
      series: [
        { name: 'Present %', data: data.department_present_rate || [] },
        { name: 'OT Hours', data: data.department_overtime_hours || [] },
        { name: 'Late', data: data.department_late_marks || [] },
        { name: 'Absent', data: data.department_absents || [] }
      ]
    });

    Object.values(state.charts).forEach((chart) => chart.render());
  };

  const showError = (message) => {
    shell.querySelectorAll('.hr-ao-grid').forEach((grid) => {
      grid.innerHTML = `<div class="hr-ao-error">${message}</div>`;
    });
  };

  frappe.call({
    method: 'hr_vfg.hr_ventureforce_global.workspace_dashboard.get_hr_attendance_overtime_workspace_data',
    callback: async function (r) {
      if (!r.message) {
        showError('No data returned for the HR attendance dashboard.');
        return;
      }
      renderKpis(r.message);
      try {
        await loadApexCharts();
        renderCharts(r.message);
      } catch (e) {
        showError('ApexCharts failed to load for the HR attendance dashboard.');
      }
    },
    error: function () {
      showError('Unable to load attendance dashboard data.');
    }
  });
})();

style:
.hr-ao-shell {
  --hr-ao-bg: linear-gradient(135deg, #fff8ef, #f7fbff);
  --hr-ao-card: #ffffff;
  --hr-ao-border: #e7e5e4;
  --hr-ao-ink: #111827;
  --hr-ao-muted: #6b7280;
  --hr-ao-shadow: 0 18px 38px rgba(15, 23, 42, 0.08);
  font-family: "Space Grotesk", "Inter", sans-serif;
  color: var(--hr-ao-ink);
}

.hr-ao-head {
  background: var(--hr-ao-bg);
  border: 1px solid var(--hr-ao-border);
  border-radius: 22px;
  padding: 22px 24px;
  display: flex;
  justify-content: space-between;
  gap: 18px;
  align-items: flex-start;
  margin-bottom: 16px;
}

.hr-ao-kicker {
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.12em;
  color: #b45309;
  margin-bottom: 6px;
}

.hr-ao-head h2 {
  margin: 0;
  font-size: 28px;
  line-height: 1.05;
}

.hr-ao-head p {
  margin: 8px 0 0 0;
  color: var(--hr-ao-muted);
  max-width: 620px;
}

.hr-ao-links {
  display: flex;
  gap: 10px;
  flex-wrap: wrap;
}

.hr-ao-link {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 10px 14px;
  border-radius: 999px;
  border: 1px solid #d6d3d1;
  background: rgba(255, 255, 255, 0.85);
  color: var(--hr-ao-ink);
  text-decoration: none;
  font-size: 13px;
  font-weight: 600;
}

.hr-ao-link-primary {
  background: #111827;
  color: #ffffff;
  border-color: #111827;
}

.hr-ao-kpis {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(170px, 1fr));
  gap: 12px;
  margin-bottom: 16px;
}

.hr-ao-kpi,
.hr-ao-card {
  background: var(--hr-ao-card);
  border: 1px solid var(--hr-ao-border);
  border-radius: 18px;
  box-shadow: var(--hr-ao-shadow);
}

.hr-ao-kpi {
  padding: 16px;
}

.hr-ao-kpi-label {
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: var(--hr-ao-muted);
  margin-bottom: 8px;
}

.hr-ao-kpi-value {
  font-size: 24px;
  font-weight: 700;
  line-height: 1;
}

.hr-ao-kpi-meta {
  margin-top: 8px;
  font-size: 12px;
  color: var(--hr-ao-muted);
}

.hr-ao-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(360px, 1fr));
  gap: 16px;
}

.hr-ao-grid-top {
  margin-bottom: 16px;
}

.hr-ao-card {
  padding: 16px;
}

.hr-ao-card-wide {
  grid-column: 1 / -1;
}

.hr-ao-card-head {
  display: flex;
  justify-content: space-between;
  align-items: baseline;
  gap: 10px;
  margin-bottom: 10px;
}

.hr-ao-card-head h3 {
  margin: 0;
  font-size: 16px;
}

.hr-ao-card-head span {
  color: var(--hr-ao-muted);
  font-size: 12px;
}

.hr-ao-chart {
  min-height: 320px;
}

.hr-ao-error {
  background: #fff7ed;
  color: #9a3412;
  border: 1px solid #fdba74;
  border-radius: 16px;
  padding: 18px;
  font-weight: 600;
}

@media (max-width: 768px) {
  .hr-ao-head {
    padding: 18px;
    flex-direction: column;
  }

  .hr-ao-head h2 {
    font-size: 24px;
  }
}
